### Distributed Trace Collector

```rust
//! Collector for aggregating distributed symbol traces.

use std::collections::HashMap;
use std::sync::{Arc, RwLock};

/// Collects and correlates spans across the distributed system.
pub struct SymbolTraceCollector {
    /// Spans indexed by trace ID.
    traces: RwLock<HashMap<TraceId, TraceRecord>>,
    /// Maximum number of traces to retain.
    max_traces: usize,
    /// Maximum age of traces before eviction.
    max_age: Duration,
    /// Clock skew tolerance for cross-region correlation.
    clock_skew_tolerance: Duration,
    /// Local region tag.
    local_region: RegionTag,
}

/// A complete trace record containing all spans.
#[derive(Clone, Debug)]
pub struct TraceRecord {
    /// The trace ID.
    trace_id: TraceId,
    /// Object ID this trace relates to.
    object_id: Option<ObjectId>,
    /// When the trace was first seen.
    first_seen: Time,
    /// When the trace was last updated.
    last_updated: Time,
    /// All spans in this trace.
    spans: Vec<SymbolSpan>,
    /// Regions involved in this trace.
    regions: Vec<RegionTag>,
    /// Whether the trace is complete (object decoded or failed).
    is_complete: bool,
}

/// Summary statistics for a trace.
#[derive(Clone, Debug)]
pub struct TraceSummary {
    /// The trace ID.
    pub trace_id: TraceId,
    /// Object ID.
    pub object_id: Option<ObjectId>,
    /// Total span count.
    pub span_count: usize,
    /// Symbols encoded.
    pub symbols_encoded: u32,
    /// Symbols transmitted.
    pub symbols_transmitted: u32,
    /// Symbols received.
    pub symbols_received: u32,
    /// Symbols dropped.
    pub symbols_dropped: u32,
    /// End-to-end latency (first encode to decode complete).
    pub end_to_end_latency: Option<Duration>,
    /// Encoding duration.
    pub encode_duration: Option<Duration>,
    /// Transmission duration (median).
    pub transmit_duration_median: Option<Duration>,
    /// Decoding duration.
    pub decode_duration: Option<Duration>,
    /// Regions traversed.
    pub regions: Vec<String>,
    /// Whether successful.
    pub success: bool,
    /// Error message if failed.
    pub error: Option<String>,
}

impl SymbolTraceCollector {
    /// Creates a new collector.
    #[must_use]
    pub fn new(local_region: RegionTag) -> Self {
        Self {
            traces: RwLock::new(HashMap::new()),
            max_traces: 10_000,
            max_age: Duration::from_secs(3600), // 1 hour
            clock_skew_tolerance: Duration::from_millis(100),
            local_region,
        }
    }

    /// Sets the maximum number of traces to retain.
    #[must_use]
    pub fn with_max_traces(mut self, max: usize) -> Self {
        self.max_traces = max;
        self
    }

    /// Sets the maximum trace age before eviction.
    #[must_use]
    pub fn with_max_age(mut self, age: Duration) -> Self {
        self.max_age = age;
        self
    }

    /// Sets the clock skew tolerance.
    #[must_use]
    pub fn with_clock_skew_tolerance(mut self, tolerance: Duration) -> Self {
        self.clock_skew_tolerance = tolerance;
        self
    }

    /// Records a span.
    pub fn record_span(&self, span: SymbolSpan, now: Time) {
        let trace_id = span.context().trace_id();

        let mut traces = self.traces.write().expect("lock poisoned");

        let record = traces.entry(trace_id).or_insert_with(|| TraceRecord {
            trace_id,
            object_id: span.object_id,
            first_seen: now,
            last_updated: now,
            spans: Vec::new(),
            regions: Vec::new(),
            is_complete: false,
        });

        record.last_updated = now;
        record.spans.push(span.clone());

        // Track regions
        let region = span.context().origin_region();
        if !record.regions.contains(region) {
            record.regions.push(region.clone());
        }

        // Check completion
        if span.kind() == SymbolSpanKind::Decode
            && matches!(span.status(), SymbolSpanStatus::Ok | SymbolSpanStatus::Error)
        {
            record.is_complete = true;
        }

        // Evict old traces if needed
        if traces.len() > self.max_traces {
            self.evict_oldest(&mut traces, now);
        }
    }

    /// Gets a trace by ID.
    #[must_use]
    pub fn get_trace(&self, trace_id: TraceId) -> Option<TraceRecord> {
        self.traces.read().expect("lock poisoned").get(&trace_id).cloned()
    }

    /// Gets a summary for a trace.
    #[must_use]
    pub fn get_summary(&self, trace_id: TraceId) -> Option<TraceSummary> {
        let traces = self.traces.read().expect("lock poisoned");
        let record = traces.get(&trace_id)?;

        let mut symbols_encoded = 0u32;
        let mut symbols_transmitted = 0u32;
        let mut symbols_received = 0u32;
        let mut symbols_dropped = 0u32;
        let mut encode_duration = None;
        let mut decode_duration = None;
        let mut transmit_durations = Vec::new();
        let mut first_encode_time: Option<Time> = None;
        let mut decode_complete_time: Option<Time> = None;
        let mut error = None;

        for span in &record.spans {
            match span.kind() {
                SymbolSpanKind::Encode => {
                    if let Some(count) = span.symbol_count {
                        symbols_encoded += count;
                    }
                    encode_duration = span.duration();
                    if first_encode_time.is_none() {
                        first_encode_time = Some(span.start_time);
                    }
                }
                SymbolSpanKind::Transmit => {
                    symbols_transmitted += 1;
                    if let Some(d) = span.duration() {
                        transmit_durations.push(d);
                    }
                    if span.status() == SymbolSpanStatus::Dropped {
                        symbols_dropped += 1;
                    }
                }
                SymbolSpanKind::Receive => {
                    symbols_received += 1;
                }
                SymbolSpanKind::Decode => {
                    decode_duration = span.duration();
                    if let Some(end) = span.end_time {
                        decode_complete_time = Some(end);
                    }
                    if span.status() == SymbolSpanStatus::Error {
                        error = span.error_message.clone();
                    }
                }
                _ => {}
            }
        }

        // Calculate end-to-end latency
        let end_to_end_latency = match (first_encode_time, decode_complete_time) {
            (Some(start), Some(end)) => {
                Some(Duration::from_nanos(end.duration_since(start)))
            }
            _ => None,
        };

        // Calculate median transmit duration
        let transmit_duration_median = if !transmit_durations.is_empty() {
            transmit_durations.sort_by_key(|t| t.as_nanos());
            Some(Duration::from_nanos(
                transmit_durations[transmit_durations.len() / 2].as_nanos(),
            ))
        } else {
            None
        };

        Some(TraceSummary {
            trace_id,
            object_id: record.object_id,
            span_count: record.spans.len(),
            symbols_encoded,
            symbols_transmitted,
            symbols_received,
            symbols_dropped,
            end_to_end_latency,
            encode_duration: encode_duration.map(|t| Duration::from_nanos(t.as_nanos())),
            transmit_duration_median,
            decode_duration: decode_duration.map(|t| Duration::from_nanos(t.as_nanos())),
            regions: record.regions.iter().map(|r| r.as_str().to_string()).collect(),
            success: record.is_complete && error.is_none(),
            error,
        })
    }

    /// Lists active traces (not yet complete).
    #[must_use]
    pub fn active_traces(&self) -> Vec<TraceId> {
        self.traces
            .read()
            .expect("lock poisoned")
            .iter()
            .filter(|(_, r)| !r.is_complete)
            .map(|(id, _)| *id)
            .collect()
    }

    /// Lists complete traces.
    #[must_use]
    pub fn complete_traces(&self) -> Vec<TraceId> {
        self.traces
            .read()
            .expect("lock poisoned")
            .iter()
            .filter(|(_, r)| r.is_complete)
            .map(|(id, _)| *id)
            .collect()
    }

    fn evict_oldest(&self, traces: &mut HashMap<TraceId, TraceRecord>, now: Time) {
        // Remove oldest complete traces first
        let mut to_remove: Vec<_> = traces
            .iter()
            .filter(|(_, r)| r.is_complete)
            .map(|(id, r)| (*id, r.last_updated))
            .collect();

        to_remove.sort_by_key(|(_, updated)| *updated);

        for (id, _) in to_remove.into_iter().take(traces.len() / 10) {
            traces.remove(&id);
        }

        // Also remove traces older than max_age
        let cutoff = now.saturating_sub_nanos(self.max_age.as_nanos() as u64);
        traces.retain(|_, r| r.last_updated >= cutoff);
    }
}
