## Integration Patterns

### Instrumenting the Sender

```rust
use asupersync::trace::distributed::*;

fn send_object_with_tracing(
    sender: &mut RaptorQSender<T>,
    collector: &SymbolTraceCollector,
    object_id: ObjectId,
    data: &[u8],
    rng: &mut DetRng,
) -> Result<ObjectParams> {
    // Create trace context
    let trace_id = TraceId::new_random(rng);
    let ctx = SymbolTraceContext::new_for_encoding(
        trace_id,
        SymbolSpanId::NIL,
        collector.local_region.clone(),
        rng,
    ).with_created_at(Time::now());

    // Start encode span
    let mut encode_span = SymbolSpan::new_encode(ctx.clone(), object_id, Time::now());

    // Encode
    let symbols = encode_with_context(data, &ctx)?;
    encode_span.set_attribute("symbol_count", symbols.len().to_string());
    encode_span.complete_ok(Time::now());
    collector.record_span(encode_span, Time::now());

    // Transmit each symbol
    for symbol in symbols {
        let tx_ctx = ctx.child(rng).with_created_at(Time::now());
        let mut tx_span = SymbolSpan::new_transmit(tx_ctx, symbol.id(), Time::now());

        match sender.send_symbol_with_context(symbol, &tx_ctx).await {
            Ok(()) => tx_span.complete_ok(Time::now()),
            Err(e) => tx_span.complete_error(Time::now(), e.to_string()),
        }

        collector.record_span(tx_span, Time::now());
    }

    Ok(params)
}
```

### Instrumenting the Receiver

```rust
fn receive_object_with_tracing(
    receiver: &mut RaptorQReceiver<S>,
    collector: &SymbolTraceCollector,
    params: &ObjectParams,
) -> Result<Vec<u8>> {
    let mut received_symbols = Vec::new();

    while received_symbols.len() < params.min_symbols_for_decode() as usize {
        let (symbol, ctx) = receiver.recv_with_context().await?;

        // Record receive span
        let mut rx_span = SymbolSpan::new_receive(ctx.clone(), symbol.id(), Time::now());
        rx_span.complete_ok(Time::now());
        collector.record_span(rx_span, Time::now());

        received_symbols.push((symbol, ctx));
    }

    // Start decode span (use context from first symbol)
    let (_, first_ctx) = &received_symbols[0];
    let decode_ctx = first_ctx.child(&mut rng);
    let mut decode_span = SymbolSpan::new_decode(
        decode_ctx,
        params.object_id,
        received_symbols.len() as u32,
        Time::now(),
    );

    match decode_symbols(&received_symbols) {
        Ok(data) => {
            decode_span.complete_ok(Time::now());
            collector.record_span(decode_span, Time::now());
            Ok(data)
        }
        Err(e) => {
            decode_span.complete_error(Time::now(), e.to_string());
            collector.record_span(decode_span, Time::now());
            Err(e)
        }
    }
}
