        let mut rng = DetRng::new(42);
        let ctx = SymbolTraceContext::new_for_encoding(
            TraceId::new_for_test(1),
            SymbolSpanId::NIL,
            RegionTag::new("test"),
            &mut rng,
        );

        let mut span = SymbolSpan::new_encode(
            ctx,
            ObjectId::new_for_test(1),
            Time::from_millis(100),
        );

        assert!(span.duration().is_none());

        span.complete_ok(Time::from_millis(150));

        assert_eq!(span.duration(), Some(Time::from_millis(50)));
    }

    #[test]
    fn test_collector_correlates_spans() {
        let collector = SymbolTraceCollector::new(RegionTag::new("test"));
        let mut rng = DetRng::new(42);

        let trace_id = TraceId::new_for_test(1);
        let ctx = SymbolTraceContext::new_for_encoding(
            trace_id,
            SymbolSpanId::NIL,
            RegionTag::new("us-east-1"),
            &mut rng,
        );

        // Record encode span
        let encode_span = SymbolSpan::new_encode(
            ctx.clone(),
            ObjectId::new_for_test(1),
            Time::from_millis(0),
        );
        collector.record_span(encode_span, Time::from_millis(0));

        // Record transmit span
        let tx_span = SymbolSpan::new_transmit(
            ctx.child(&mut rng),
            SymbolId::new_for_test(1, 0, 0),
            Time::from_millis(10),
        );
        collector.record_span(tx_span, Time::from_millis(10));

        let record = collector.get_trace(trace_id).unwrap();
        assert_eq!(record.spans.len(), 2);
    }

    #[test]
    fn test_trace_summary_calculations() {
        let collector = SymbolTraceCollector::new(RegionTag::new("test"));
        let mut rng = DetRng::new(42);
        let trace_id = TraceId::new_for_test(1);
        let object_id = ObjectId::new_for_test(1);

        let ctx = SymbolTraceContext::new_for_encoding(
            trace_id,
            SymbolSpanId::NIL,
            RegionTag::new("sender"),
            &mut rng,
        );

        // Encode span
        let mut encode_span = SymbolSpan::new_encode(ctx.clone(), object_id, Time::from_millis(0));
        encode_span.symbol_count = Some(10);
        encode_span.complete_ok(Time::from_millis(100));
        collector.record_span(encode_span, Time::from_millis(100));

        // Transmit spans
        for i in 0..10 {
            let mut tx_span = SymbolSpan::new_transmit(
                ctx.child(&mut rng),
                SymbolId::new_for_test(1, 0, i),
                Time::from_millis(100 + i as u64 * 10),
            );
            tx_span.complete_ok(Time::from_millis(150 + i as u64 * 10));
            collector.record_span(tx_span, Time::from_millis(150 + i as u64 * 10));
        }

        // Decode span
        let mut decode_span = SymbolSpan::new_decode(
            ctx.child(&mut rng),
            object_id,
            10,
            Time::from_millis(300),
        );
        decode_span.complete_ok(Time::from_millis(400));
        collector.record_span(decode_span, Time::from_millis(400));

        let summary = collector.get_summary(trace_id).unwrap();
        assert_eq!(summary.symbols_encoded, 10);
        assert_eq!(summary.symbols_transmitted, 10);
        assert!(summary.success);
        assert!(summary.end_to_end_latency.is_some());
    }
}
